/** @jsxImportSource @emotion/react */
import { css } from '@emotion/react';

type CardProps = React.ButtonHTMLAttributes<HTMLDivElement> & {
  title?: string;
  description?: React.ReactNode;
  image?: string;
};

export function Card({ title, description, image, ...containerProps }: CardProps) {
  return (
    <div {...containerProps}>
      <div>
        <h2>{title}</h2>
        <p>{description}</p>
      </div>
      <img src={image} />
    </div>
  );
}
